// Navigation Structure Contract
// Files: src/navigation/types.ts, src/navigation/RootNavigator.tsx, src/navigation/MainTabs.tsx, src/navigation/index.tsx

// Dependencies (in package.json):
// - @react-navigation/native: ^7.1.33
// - @react-navigation/bottom-tabs: ^7.15.5
// - @react-navigation/native-stack: ^7.14.4
// - react-native-screens: ~4.23.0
// - react-native-safe-area-context: ~5.6.2

// Import from '@/navigation'
export type RootStackParamList = {
  Login: undefined;
  Main: NavigatorScreenParams<MainTabParamList> | undefined;
  EntryEdit: { entryId: string };
};

export type MainTabParamList = {
  Timer: undefined;
  History: { categoryId?: string; dateStart?: string; dateEnd?: string } | undefined;
  Analytics: undefined;
  Categories: undefined;
  Goals: { month?: string } | undefined;
  Settings: undefined;
};

export type RootStackScreenProps<T extends keyof RootStackParamList>;
export type MainTabScreenProps<T extends keyof MainTabParamList>;

export function NavigationProvider(props: { children?: React.ReactNode }): React.ReactElement;
export function RootNavigator(): React.ReactElement;
export function MainTabs(): React.ReactElement;
export const navigationTheme: NavigationTheme;

// Behavior notes:
// - NavigationProvider wraps app with NavigationContainer and custom dark theme
// - RootNavigator conditionally shows Login (unauthenticated) or Main (authenticated)
// - EntryEdit is a modal accessible from anywhere when authenticated
// - MainTabs has 6 tabs: Timer, History, Analytics, Categories, Goals, Settings
// - Tab icons use custom Icon component with Unicode symbols (fallback for @expo/vector-icons)
// - Global ReactNavigation.RootParamList declaration enables typed useNavigation()
